def process_image(image_bytes, content_type=None):
    """
    Placeholder for image processing logic.
    Replace with actual processing such as resizing, thumbnail generation,
    metadata extraction, OCR, moderation, etc.
    """
    return image_bytes


def send_notification(message, subject="Image Processing Complete"):
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not configured; skipping notification")
        return

    try:
        sns.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject[:100],
            Message=json.dumps(message, default=str),
        )
    except ClientError as e:
        logger.exception("Failed to publish SNS notification: %s", e)
        raise


def lambda_handler(event, context):
    logger.info("Received event: %s", json.dumps(event))

    results = []

    for record in event.get("Records", []):
        try:
            bucket = record["s3"]["bucket"]["name"]
            key = unquote_plus(record["s3"]["object"]["key"])

            logger.info("Processing object s3://%s/%s", bucket, key)

            response = s3.get_object(Bucket=bucket, Key=key)
            original_bytes = response["Body"].read()
            content_type = response.get("ContentType", "application/octet-stream")

            processed_bytes = process_image(original_bytes, content_type=content_type)

            if OUTPUT_BUCKET:
                output_bucket = OUTPUT_BUCKET
            else:
                output_bucket = bucket

            filename = key.split("/")[-1]
            output_key = f"{PROCESSED_PREFIX}{filename}"

            s3.put_object(
                Bucket=output_bucket,
                Key=output_key,
                Body=processed_bytes,
                ContentType=content_type,
            )

            result = {
                "input_bucket": bucket,
                "input_key": key,
                "output_bucket": output_bucket,
                "output_key": output_key,
                "status": "success",
            }
            results.append(result)

            logger.info("Successfully processed %s", result)

            send_notification(
                {
                    "event": "image_processed",
                    "input_bucket": bucket,
                    "input_key": key,
                    "output_bucket": output_bucket,
                    "output_key": output_key,
                    "status": "success",
                }
            )

        except Exception as e:
            logger.exception("Error processing record: %s", e)
            failure_result = {
                "status": "error",
                "error": str(e),
                "record": record,
            }
            results.append(failure_result)

            try:
                send_notification(
                    {
                        "event": "image_processing_failed",
                        "status": "error",
                        "error": str(e),
                        "record": record,
                    },
                    subject="Image Processing Failed",
                )
            except Exception:
                logger.exception("Failed to send failure notification")

    return {
        "statusCode": 200,
        "body": json.dumps(
            {
                "message": "Processing completed",
                "results": results,
            }
        ),
    }